package com.archivenexus.backend.ai;
import com.archivenexus.backend.ai.ManufacturingAiModels.*;import com.archivenexus.backend.service.NexusStateService;import org.springframework.stereotype.Component;import java.util.*;
@Component public class CrossDomainRootCauseAgent implements ManufacturingAgent{
 private final NexusStateService nexus;public CrossDomainRootCauseAgent(NexusStateService nexus){this.nexus=nexus;}
 public String getName(){return "CrossDomainRootCauseAgent";}public boolean supports(Intent intent){return intent==Intent.CROSS_DOMAIN;}public int getPriority(){return 90;}
 public AgentResult analyze(AgentContext c){long s=System.nanoTime();String f=c.selectedFactoryId();long defects=nexus.inspections().stream().filter(x->f==null||f.equals(x.factoryId())).filter(x->x.defectRate()>=0.05).count();long production=nexus.productionOrders().stream().filter(x->f==null||f.equals(x.factoryId())).filter(x->x.producedQuantity()<x.targetQuantity()*0.8).count();long stock=nexus.inventoryItems().stream().filter(x->x.quantity()<=x.safetyStock()).count();long maintenance=nexus.maintenanceEvents().stream().filter(x->f==null||f.equals(x.factoryId())).filter(x->"OPEN".equals(x.status())).count();long delayed=nexus.shipments().stream().filter(x->f==null||f.equals(x.factoryId())).filter(x->"DELAYED".equals(x.status())).count();List<AgentEvidence> evidence=List.of(ev("품질 이상",defects,"qualityInspections"),ev("생산 미달",production,"productionOrders"),ev("재고 위험",stock,"inventoryItems"),ev("미처리 정비",maintenance,"maintenanceEvents"),ev("출하 지연",delayed,"logisticsShipments"));long affected=java.util.stream.LongStream.of(defects,production,stock,maintenance,delayed).filter(v->v>0).count();if(affected<2)return new AgentResult(getName(),Intent.CROSS_DOMAIN,"도메인 간 근본 원인을 연결할 충분한 동시 이상 근거가 없습니다.",evidence,List.of(),0.45,elapsed(s),AgentExecutionStatus.INSUFFICIENT_DATA,null,false);return new AgentResult(getName(),Intent.CROSS_DOMAIN,"품질→생산→재고→정비→출하 중 "+affected+"개 영역에서 동시 이상 근거가 확인되었습니다.",evidence,List.of("PM 승인 후 정비·재고 할당·출하 우선순위를 하나의 복구 Workflow로 실행하세요."),0.86,elapsed(s),AgentExecutionStatus.COMPLETED,null,true);}
 private AgentEvidence ev(String label,long value,String source){return new AgentEvidence("CROSS_DOMAIN",label,value+"건",source);}private long elapsed(long s){return(System.nanoTime()-s)/1_000_000;}
}
